INSERT INTO public.simulados (id,nome,descricao,total_questoes,ordem,ativo) VALUES ('99999999-9999-9999-9999-999999999999','Simulado ENEM — Prova 9','Prova mista com 30 questões no estilo ENEM',30,9,true);
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',1,'HUMANAS','O quilombo não era apenas um refúgio de escravizados fugidos, mas um espaço de reconstrução cultural, social e econômica. Nesses locais, organizavam-se estruturas agrícolas, redes de comércio com vilas vizinhas e celebrações religiosas que mesclavam tradições africanas e elementos locais, desafiando a lógica mercantilista e escravocrata da metrópole.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',2,'NATUREZA','O uso indiscriminado de defensivos agrícolas organoclorados pode resultar na contaminação de recursos hídricos. Esses compostos possuem alta estabilidade química e são lipossolúveis, o que impede sua rápida eliminação pelos organismos vivos. Ao longo da cadeia alimentar, observa-se um fenômeno em que a concentração dessas substâncias aumenta progressivamente a cada nível trófico.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',3,'MATEMATICA','Um arquiteto está desenvolvendo o projeto de um condomínio residencial e fixou a escala da maquete em 1:150. No projeto físico, a área de lazer principal do condomínio, que tem o formato de um retângulo perfeito, apresenta as medidas de 12 centímetros de largura por 20 centímetros de comprimento.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',4,'LINGUAGENS','Propaganda institucional: ''Não passe a bola para a frente. O mosquito da dengue se reproduz em qualquer poça de água limpa parada. Verifique suas calhas, tampe seus tonéis e mude o hábito. A saúde do seu bairro depende do seu quintal. Denuncie focos imóveis.''
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',5,'HUMANAS','A gentrificação é um processo de transformação urbana que remodela áreas periféricas ou historicamente degradadas através da inserção de novos empreendimentos imobiliários, comércio de luxo e infraestrutura moderna. Embora promova a valorização estética e econômica da região, o processo frequentemente resulta no encarecimento do custo de vida local.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',6,'NATUREZA','Nas estações de tratamento de água (ETA), o fluido captado dos rios passa por diversas etapas antes de ser distribuído. Uma das fases iniciais consiste na adição de sulfato de alumínio e cal, que reagem formando um precipitado gelatinoso. Esse precipitado aglutina as partículas finas de sujeira que estavam em suspensão, tornando-as maiores e mais pesadas.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',7,'MATEMATICA','Um pequeno comércio registrou o número de reclamações diárias recebidas pelo serviço de atendimento ao cliente (SAC) durante uma semana. Os dados coletados foram: 2, 5, 3, 2, 8, 2 e 6. O gerente deseja apresentar a moda desse conjunto de dados no relatório de desempenho.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',8,'NATUREZA','Os radares estáticos de controle de velocidade das vias urbanas operam com base em sensores embutidos no asfalto (laços indutivos). Quando as rodas dianteiras do veículo passam pelo primeiro sensor, um cronômetro digital de alta precisão é disparado e, ao cruzar o segundo sensor, posicionado a uma distância fixa de 3 metros, o tempo é interrompido.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',9,'LINGUAGENS','Fala de um personagem de uma comunidade pesqueira tradicional: ''A gente num pode dár bobeira com o mar não, dotô. Ele conhece quem é da terra e quem é da água. Se o vento sul virá de supetão, as canoa tem que tá tudo recolhida, se não o prejuízo é certo e o mar cobra seu preço.''
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',10,'HUMANAS','Theodor Adorno e Max Horkheimer cunharam o termo ''Indústria Cultural'' para explicar a transformação da arte e da cultura em mercadorias seriadas e massificadas. Segundo os autores, a padronização dos bens culturais (como músicas, filmes e programas de TV) não visa a emancipação intelectual, mas sim a passividade do espectador.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',11,'HUMANAS','No século XVII, a Holanda vivenciou a chamada ''Mania das Tulipas'', considerada por muitos historiadores econômicos como a primeira bolha especulativa registrada. Contratos futuros de bulbos de tulipas raras alcançaram preços exorbitantes, equivalentes a propriedades inteiras e anos de salários de um trabalhador, impulsionados pela crença irrestrita de que os preços continuariam subindo indefinidamente, até o colapso abrupto do mercado em 1637.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',12,'NATUREZA','Na estética automotiva profissional de alto nível, o processo de proteção da pintura geralmente envolve a aplicação de selantes sintéticos ou vitrificadores à base de sílica (SiO2). Diferentemente das ceras naturais de carnaúba, que atuam por deposição superficial, os vitrificadores criam ligações químicas diretas com o verniz automotivo, formando uma rede tridimensional altamente resistente a intempéries e produtos químicos agressivos.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',13,'HUMANAS','O bioma Amazônico é o maior ecossistema tropical do mundo, caracterizado por floresta ombrófila densa e uma complexa bacia hidrográfica. Imagens de satélite revelam, contudo, que a dinâmica de expansão da fronteira agrícola gerou o ''Arco do Desmatamento''. A supressão dessa cobertura vegetal não afeta apenas a biodiversidade local, mas altera a dinâmica climática de regiões distantes do Brasil, como o Centro-Oeste, o Sudeste e o Sul.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',14,'MATEMATICA','Um jovem empreendedor elaborou um projeto focado em ''flip'' (compra, valorização e revenda rápida de itens). Ele inicia com um capital de R$ 100,00 e, a cada ciclo de operação que dura uma semana, consegue reinvestir todo o montante obtido, alcançando sempre um lucro líquido de 50% sobre o capital investido na respectiva semana.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',15,'NATUREZA','A infraestrutura global de internet e a transmissão de dados físicos do modelo OSI dependem largamente dos cabos de fibra óptica, instalados inclusive em leitos oceânicos. Esses cabos finíssimos são compostos por um núcleo de vidro (ou plástico polimérico) por onde a luz viaja, envolto por um revestimento (casca) também transparente, mas com propriedades ópticas rigorosamente distintas, garantindo que o pulso luminoso percorra longas distâncias sem escapar pelas laterais.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',16,'LINGUAGENS','A evolução das Inteligências Artificiais geradoras de imagens e vídeos transformou radicalmente o fazer artístico. Na elaboração de ''prompts'' (comandos em texto) refinados, criadores utilizam hoje jargões avançados da fotografia e do cinema — como ''iluminação volumétrica'', ''cel-shaded'', ''render em 8k'', ''foco raso'' ou ''ângulo contra-plongée'' — para guiar os algoritmos até o resultado visual desejado.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',17,'NATUREZA','Para resolver mistérios arqueológicos, documentar fósseis de biomas antigos ou analisar ''OOPArts'' (artefatos históricos fora de contexto e tempo) que contêm matéria orgânica, os pesquisadores frequentemente recorrem à datação por Carbono-14 ($^{14}C$). Esse isótopo é produzido constantemente na alta atmosfera, entra no ciclo biológico por meio da fotossíntese e da alimentação e, após a morte do organismo, passa a diminuir sua concentração.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',18,'MATEMATICA','Na arquitetura e organização de redes de computadores, para que dispositivos se comuniquem localmente ou via internet, eles recebem um endereço lógico. No padrão IPv4 (Internet Protocol version 4), esse endereço é estruturado em 4 blocos (octetos) separados por pontos, como no formato ''X.Y.Z.W''. O sistema estabelece que cada um desses quatro blocos pode assumir um valor decimal inteiro de 0 a 255.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',19,'LINGUAGENS','Ethical hacking and penetration testing (pentesting) involve authorized attempts to breach a company’s digital security network. Unlike malicious attackers, ethical hackers operate legally under a specific scope of work, identifying critical vulnerabilities before they can be exploited by cybercriminals, and providing detailed engineering reports on how to patch them.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',20,'HUMANAS','A consolidação de protocolos de criptomoedas no final dos anos 2000 introduziu as finanças descentralizadas (DeFi) e a tecnologia *blockchain*. Essa estrutura distribui a validação das operações em uma rede global (nós) via criptografia e consenso matemático, eliminando estruturalmente a figura de um agente validador intermediário.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',21,'MATEMATICA','Uma bola é lançada para cima e sua altura, em metros, é descrita pela função h(t) = -t² + 6t + 7, em que t representa o tempo em segundos.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',22,'HUMANAS','A Revolução Industrial iniciou-se na Inglaterra durante o século XVIII e provocou profundas transformações econômicas e sociais.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',23,'NATUREZA','Em um ecossistema, a energia flui entre os organismos por meio das relações alimentares.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',24,'LINGUAGENS','O Naturalismo buscou explicar o comportamento humano por meio de fatores biológicos, hereditários e sociais.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',25,'MATEMATICA','Uma sequência numérica apresenta os termos 5, 8, 11, 14...
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',26,'HUMANAS','A industrialização modifica a organização econômica e espacial dos territórios.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',27,'NATUREZA','Um objeto possui massa de 400 g e volume de 200 cm³.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',28,'LINGUAGENS','As funções da linguagem variam conforme a intenção comunicativa predominante.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',29,'HUMANAS','A socialização é o processo pelo qual os indivíduos aprendem valores, normas e comportamentos aceitos em uma sociedade.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('99999999-9999-9999-9999-999999999999',30,'NATUREZA','As ligações químicas permitem a formação de substâncias estáveis por meio da interação entre átomos.
INSERT INTO public.simulados (id,nome,descricao,total_questoes,ordem,ativo) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa','Simulado ENEM — Prova 10','Prova mista com 40 questões no estilo ENEM',40,10,true);
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',1,'MATEMATICA','Uma equipe de voluntários distribuiu 240 cestas básicas igualmente entre 12 comunidades atendidas por um programa social.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',2,'HUMANAS','O Renascimento foi um movimento cultural que se desenvolveu na Europa entre os séculos XIV e XVI, valorizando a razão, a observação da natureza e a herança clássica greco-romana.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',3,'NATUREZA','As células são consideradas as unidades básicas dos seres vivos.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',4,'LINGUAGENS','As figuras de linguagem ampliam os sentidos dos textos e tornam a comunicação mais expressiva.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',5,'MATEMATICA','Uma loja oferece desconto de 15% em um produto que custa R$ 400.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',6,'HUMANAS','Os diferentes tipos climáticos são influenciados por fatores como latitude, altitude e massas de ar.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',7,'NATUREZA','Um automóvel percorre 180 km em 3 horas mantendo velocidade constante.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',8,'LINGUAGENS','A leitura eficiente exige compreender informações explícitas e implícitas presentes em um texto.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',9,'HUMANAS','Sócrates defendia o conhecimento por meio do diálogo e da reflexão crítica.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',10,'NATUREZA','Misturas podem ser classificadas em homogêneas ou heterogêneas conforme o número de fases observadas.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',11,'MATEMATICA','Uma empresa de transporte por aplicativo cobra uma tarifa composta por uma taxa fixa de R$ 8,00 mais R$ 2,50 por quilômetro percorrido.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',12,'HUMANAS','Durante o governo de Getúlio Vargas ocorreram profundas transformações econômicas e trabalhistas no Brasil, com destaque para a criação de leis voltadas à proteção dos trabalhadores urbanos.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',13,'NATUREZA','As características hereditárias são transmitidas dos pais para os filhos por meio dos genes presentes nos cromossomos.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',14,'LINGUAGENS','O Realismo surgiu como reação ao Romantismo, buscando retratar a sociedade de maneira objetiva e crítica.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',15,'MATEMATICA','Um terreno retangular possui 20 metros de comprimento e 15 metros de largura.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',16,'HUMANAS','A globalização intensificou os fluxos de mercadorias, capitais, informações e pessoas em escala mundial.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',17,'NATUREZA','Um corpo de massa igual a 5 kg é submetido a uma força resultante de 20 N.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',18,'LINGUAGENS','A língua portuguesa apresenta diferentes formas de uso de acordo com fatores sociais, regionais e culturais.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',19,'HUMANAS','O Iluminismo foi um movimento intelectual que defendia o uso da razão como instrumento para compreender e transformar a sociedade.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',20,'NATUREZA','O pH é uma escala utilizada para medir a acidez ou basicidade de soluções aquosas.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',21,'MATEMATICA','Uma urna contém 5 bolas vermelhas e 3 bolas azuis. Uma bola será retirada aleatoriamente.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',22,'HUMANAS','A Revolução Francesa, iniciada em 1789, promoveu profundas transformações políticas e sociais, influenciando diversos países ao redor do mundo.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',23,'NATUREZA','A fotossíntese é um processo fundamental para a manutenção da vida na Terra, pois produz matéria orgânica e libera oxigênio para a atmosfera.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',24,'LINGUAGENS','O Romantismo brasileiro valorizou a subjetividade, o nacionalismo e a idealização amorosa.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',25,'MATEMATICA','Uma caixa possui formato cúbico e aresta medindo 4 cm.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',26,'HUMANAS','A taxa de natalidade e a taxa de mortalidade são importantes indicadores demográficos utilizados para analisar a dinâmica populacional.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',27,'NATUREZA','Uma força de 50 N desloca um objeto por uma distância de 4 metros na mesma direção da força aplicada.
INSERT INTO public.questoes_simulado (simulado_id,numero,area,enunciado,alt_a,alt_b,alt_c,alt_d,alt_e,resposta_correta) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',28,'LINGUAGENS','As conjunções são palavras responsáveis por estabelecer relações de sentido entre orações e termos.
